Here is a broken service. Identify all the RxJS anti-patterns and rewrite it correctly:

import { Injectable } from '@angular/core';
import { Subject, switchMap, tap, toSignal } from 'rxjs';
import { inject } from '@angular/core';
import { SDKService } from '@flaps/core';
import { signal, computed } from '@angular/core';

@Injectable({ providedIn: 'root' })
export class BrokenDriversService {
  private sdk = inject(SDKService);

  private _refresh = new Subject<void>();
  private _drivers = signal<string[]>([]);

  drivers$ = this._refresh.pipe(
    switchMap(() => this.sdk.currentArag),
    switchMap((arag) => arag.getDrivers()),
    tap((drivers) => this._drivers.set(drivers)),
  );

  drivers = toSignal(this.drivers$);
  hasDrivers = computed(() => this._drivers().length > 0);

  refresh() {
    this._refresh.next();
  }
}
